prompts.raw:
function ({ vars }                                  )         {
  const previousFindings                = vars.previousFindings
    ? JSON.parse(vars.previousFindings)
    : [];

  const ctx               = {
    brief: vars.brief,
    jurisdiction: vars.jurisdiction || undefined,
    round: Number(vars.round) || 1,
    previousFindings,
  };

  return buildAttackerPrompt(ctx);
}

